use base::{BaseConfig, Algorithm};
use crate::harness::{self, BenchResult};

// ---------------------------------------------------------------------------
// Matrix Multiplication Benchmark
//
// Compares Rust, Burn (NdArray), and Base (Cranelift JIT) for square matmul.
//
// Algorithm CLIF IR is generated by Lean at build time (see lean/ directory).
// ---------------------------------------------------------------------------

type B = burn::backend::NdArray<f32>;

const MATMUL_ALGORITHM: &[u8] =
    include_bytes!(concat!(env!("OUT_DIR"), "/matmul_algorithm.bin"));

fn load_algorithm() -> (BaseConfig, Algorithm) {
    bincode::deserialize(MATMUL_ALGORITHM).expect("Failed to deserialize matmul algorithm")
}

fn gen_floats(n: usize, seed: u64) -> Vec<f32> {
    let mut state = seed;
    let mut out = Vec::with_capacity(n);
    for _ in 0..n {
        state = state
            .wrapping_mul(6364136223846793005)
            .wrapping_add(1442695040888963407);
        let bits = (state >> 33) as i32;
        let f = (bits as f32 / i32::MAX as f32) * 2.0 - 1.0;
        out.push(f);
    }
    out
}

fn rust_matmul(a: &[f32], b: &[f32], m: usize, k: usize, n: usize) -> f64 {
    let mut c = vec![0.0f32; m * n];
    for i in 0..m {
        for p in 0..k {
            let a_val = a[i * k + p];
            for j in 0..n {
                c[i * n + j] += a_val * b[p * n + j];
            }
        }
    }
    c.iter().map(|&x| x as f64).sum()
}

fn burn_matmul(a: &[f32], b: &[f32], m: usize, k: usize, n: usize) -> f64 {
    use burn::tensor::{Tensor, TensorData};
    let device = Default::default();
    let a_t = Tensor::<B, 2>::from_data(
        TensorData::new(a.to_vec(), [m, k]),
        &device,
    );
    let b_t = Tensor::<B, 2>::from_data(
        TensorData::new(b.to_vec(), [k, n]),
        &device,
    );
    let c_t = a_t.matmul(b_t);
    c_t.sum().into_scalar() as f64
}

/// Build payload: [M:u32][K:u32][N:u32][A floats...][B floats...]
fn build_payload(a: &[f32], b: &[f32], m: usize, k: usize, n: usize) -> Vec<u8> {
    let mut payload = Vec::with_capacity(12 + (a.len() + b.len()) * 4);
    payload.extend_from_slice(&(m as u32).to_le_bytes());
    payload.extend_from_slice(&(k as u32).to_le_bytes());
    payload.extend_from_slice(&(n as u32).to_le_bytes());
    for &v in a {
        payload.extend_from_slice(&v.to_le_bytes());
    }
    for &v in b {
        payload.extend_from_slice(&v.to_le_bytes());
    }
    payload
}

fn close_enough(a: f64, b: f64) -> bool {
    if a.is_nan() || b.is_nan() {
        return false;
    }
    let diff = (a - b).abs();
    let mag = a.abs().max(b.abs()).max(1.0);
    diff / mag < 0.02
}

pub fn run(iterations: usize) -> Vec<BenchResult> {
    let sizes: &[usize] = &[128, 256, 512, 1024];
    let mut results = Vec::new();

    // JIT compile once
    let (config, alg) = load_algorithm();
    let mut base_instance = base::Base::new(config).expect("Base::new failed");

    for &n in sizes {
        let total = n * n * 2;
        let data = gen_floats(total, 42);
        let a = &data[..n * n];
        let b = &data[n * n..];

        let payload = build_payload(a, b, n, n, n);

        // Raw Rust
        let rust_ms = harness::median_of(iterations, || {
            let start = std::time::Instant::now();
            std::hint::black_box(rust_matmul(a, b, n, n, n));
            start.elapsed().as_secs_f64() * 1000.0
        });

        // Burn (NdArray CPU)
        let burn_ms = {
            use burn::tensor::{Tensor, TensorData};
            let device = Default::default();
            let a_t = Tensor::<B, 2>::from_data(TensorData::new(a.to_vec(), [n, n]), &device);
            let b_t = Tensor::<B, 2>::from_data(TensorData::new(b.to_vec(), [n, n]), &device);
            harness::median_of(iterations, || {
                let start = std::time::Instant::now();
                let c_t = a_t.clone().matmul(b_t.clone());
                std::hint::black_box(c_t.sum().into_scalar());
                start.elapsed().as_secs_f64() * 1000.0
            })
        };

        // Base (Cranelift JIT) — execute with payload, read result from out buffer
        let mut out_buf = [0u8; 8];

        // Warmup
        let _ = base_instance.execute_into(&alg, &payload, &mut out_buf);

        let base_ms = harness::median_of(iterations, || {
            let start = std::time::Instant::now();
            let _ = base_instance.execute_into(&alg, &payload, &mut out_buf);
            start.elapsed().as_secs_f64() * 1000.0
        });

        let base_result = f64::from_le_bytes(out_buf);
        let rust_check = rust_matmul(a, b, n, n, n);
        let burn_check = burn_matmul(a, b, n, n, n);
        let verified = Some(
            close_enough(rust_check, burn_check) && close_enough(rust_check, base_result),
        );

        results.push(BenchResult {
            name: format!("MatMul ({}x{})", n, n),
            python_ms: Some(burn_ms),
            rust_ms: Some(rust_ms),
            base_ms,
            verified,
            actions: None,
        });
    }

    results
}
